/**
 * @suppress
 */
public object FfiConverterTypeMadarCore: FfiConverter<MadarCore, Pointer> {

    override fun lower(value: MadarCore): Pointer {
        return value.uniffiClonePointer()
    }

    override fun lift(value: Pointer): MadarCore {
        return MadarCore(value)
    }

    override fun read(buf: ByteBuffer): MadarCore {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: MadarCore) = 8UL

    override fun write(value: MadarCore, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}



