/**
 * The screen the host should show, decided by the core (PLAN Â§R11). The host
 * consults this only at deliberate transitions (cold start, post-login,
 * post-open/close-shift, sign-out) â€” never as a side effect of connectivity.
 */
sealed class AppRoute {
    
    /**
     * Till not bound to a branch â†’ manager device-setup.
     */
    object DeviceSetup : AppRoute()
    
    
    /**
     * Configured but signed out â†’ teller/waiter PIN login.
     */
    object Login : AppRoute()
    
    
    /**
     * Signed in, no open shift â†’ open-shift screen.
     */
    object OpenShift : AppRoute()
    
    
    /**
     * Signed in with an open shift â†’ order screen.
     */
    object Order : AppRoute()
    
    
    /**
     * Device run as a kitchen display â†’ the KDS for `station_id` (no shift needed).
     */
    data class KitchenDisplay(
        val `stationId`: kotlin.String) : AppRoute() {
        companion object
    }
    
    /**
     * A signed-in WAITER (holds no shift) â†’ the open-tickets / take-order screen.
     */
    object WaiterTickets : AppRoute()
    
    

    
    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeAppRoute : FfiConverterRustBuffer<AppRoute>{
    override fun read(buf: ByteBuffer): AppRoute {
        return when(buf.getInt()) {
            1 -> AppRoute.DeviceSetup
            2 -> AppRoute.Login
            3 -> AppRoute.OpenShift
            4 -> AppRoute.Order
            5 -> AppRoute.KitchenDisplay(
                FfiConverterString.read(buf),
                )
            6 -> AppRoute.WaiterTickets
            else -> throw RuntimeException("invalid enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: AppRoute) = when(value) {
        is AppRoute.DeviceSetup -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
        is AppRoute.Login -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
        is AppRoute.OpenShift -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
        is AppRoute.Order -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
        is AppRoute.KitchenDisplay -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`stationId`)
            )
        }
        is AppRoute.WaiterTickets -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
    }

    override fun write(value: AppRoute, buf: ByteBuffer) {
        when(value) {
            is AppRoute.DeviceSetup -> {
                buf.putInt(1)
                Unit
            }
            is AppRoute.Login -> {
                buf.putInt(2)
                Unit
            }
            is AppRoute.OpenShift -> {
                buf.putInt(3)
                Unit
            }
            is AppRoute.Order -> {
                buf.putInt(4)
                Unit
            }
            is AppRoute.KitchenDisplay -> {
                buf.putInt(5)
                FfiConverterString.write(value.`stationId`, buf)
                Unit
            }
            is AppRoute.WaiterTickets -> {
                buf.putInt(6)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }
}







sealed class CoreException: kotlin.Exception() {
    
    /**
     * An online-only op was attempted while disconnected. Hot-path *commands*
     * never return this â€” they queue to the outbox instead.
     */
    class Offline(
        
        val `detail`: kotlin.String
        ) : CoreException() {
        override val message
            get() = "detail=${ `detail` }"
    }
    
    /**
     * 401 + refresh failed â†’ the host should surface sign-in.
     */
    class Unauthenticated(
        
        val `detail`: kotlin.String
        ) : CoreException() {
        override val message
            get() = "detail=${ `detail` }"
    }
    
    class Forbidden(
        
        val `resource`: kotlin.String, 
        
        val `action`: kotlin.String
        ) : CoreException() {
        override val message
            get() = "resource=${ `resource` }, action=${ `action` }"
    }
    
    /**
     * Local validation: mode invariants, empty cart, future-dated event, â€¦
     */
    class Validation(
        
        val `field`: kotlin.String, 
        
        val `detail`: kotlin.String
        ) : CoreException() {
        override val message
            get() = "field=${ `field` }, detail=${ `detail` }"
    }
    
    class Server(
        
        val `status`: kotlin.UShort, 
        
        val `code`: kotlin.String, 
        
        val `detail`: kotlin.String
        ) : CoreException() {
        override val message
            get() = "status=${ `status` }, code=${ `code` }, detail=${ `detail` }"
    }
    
    /**
     * 5xx / timeout â€” sync already retries; informational for the host.
     */
    class Transient(
        
        val `detail`: kotlin.String
        ) : CoreException() {
        override val message
            get() = "detail=${ `detail` }"
    }
    
    /**
     * Store/migration/serde, or an FFI-version mismatch.
     */
    class Internal(
        
        val `detail`: kotlin.String
        ) : CoreException() {
        override val message
            get() = "detail=${ `detail` }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<CoreException> {
        override fun lift(error_buf: RustBuffer.ByValue): CoreException = FfiConverterTypeCoreError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeCoreError : FfiConverterRustBuffer<CoreException> {
    override fun read(buf: ByteBuffer): CoreException {
        

        return when(buf.getInt()) {
            1 -> CoreException.Offline(
                FfiConverterString.read(buf),
                )
            2 -> CoreException.Unauthenticated(
                FfiConverterString.read(buf),
                )
            3 -> CoreException.Forbidden(
                FfiConverterString.read(buf),
                FfiConverterString.read(buf),
                )
            4 -> CoreException.Validation(
                FfiConverterString.read(buf),
                FfiConverterString.read(buf),
                )
            5 -> CoreException.Server(
                FfiConverterUShort.read(buf),
                FfiConverterString.read(buf),
                FfiConverterString.read(buf),
                )
            6 -> CoreException.Transient(
                FfiConverterString.read(buf),
                )
            7 -> CoreException.Internal(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: CoreException): ULong {
        return when(value) {
            is CoreException.Offline -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`detail`)
            )
            is CoreException.Unauthenticated -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`detail`)
            )
            is CoreException.Forbidden -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`resource`)
                + FfiConverterString.allocationSize(value.`action`)
            )
            is CoreException.Validation -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`field`)
                + FfiConverterString.allocationSize(value.`detail`)
            )
            is CoreException.Server -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterUShort.allocationSize(value.`status`)
                + FfiConverterString.allocationSize(value.`code`)
                + FfiConverterString.allocationSize(value.`detail`)
            )
            is CoreException.Transient -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`detail`)
            )
            is CoreException.Internal -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`detail`)
            )
        }
    }

    override fun write(value: CoreException, buf: ByteBuffer) {
        when(value) {
            is CoreException.Offline -> {
                buf.putInt(1)
                FfiConverterString.write(value.`detail`, buf)
                Unit
            }
            is CoreException.Unauthenticated -> {
                buf.putInt(2)
                FfiConverterString.write(value.`detail`, buf)
                Unit
            }
            is CoreException.Forbidden -> {
                buf.putInt(3)
                FfiConverterString.write(value.`resource`, buf)
                FfiConverterString.write(value.`action`, buf)
                Unit
            }
            is CoreException.Validation -> {
                buf.putInt(4)
                FfiConverterString.write(value.`field`, buf)
                FfiConverterString.write(value.`detail`, buf)
                Unit
            }
            is CoreException.Server -> {
                buf.putInt(5)
                FfiConverterUShort.write(value.`status`, buf)
                FfiConverterString.write(value.`code`, buf)
                FfiConverterString.write(value.`detail`, buf)
                Unit
            }
            is CoreException.Transient -> {
                buf.putInt(6)
                FfiConverterString.write(value.`detail`, buf)
                Unit
            }
            is CoreException.Internal -> {
                buf.putInt(7)
                FfiConverterString.write(value.`detail`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}



